const PARENT_ID='7:2';
const parent=await relay.getNodeByIdAsync(PARENT_ID);
if(!parent||parent.type!=='FRAME') return { ok:false, err:'not frame'};
const payloads=[
  { id:2, b64:"" }
];
let inserted=0;
for(const row of payloads){
  const img=relay.createImage(relay.base64Decode(row.b64));
  const sz=await img.getSizeAsync();
  const targetW=Math.max(parent.width||457,457);
  const h = sz.height * (targetW / sz.width);
  const rect = relay.createRectangle();
  rect.name='scheme_a_'+row.id;
  rect.layoutSizingHorizontal='FILL';
  rect.layoutSizingVertical='FIXED';
  rect.resize(targetW,h);
  rect.fills=[{type:'IMAGE', imageHash:img.hash, scaleMode:'FILL'}];
  parent.appendChild(rect);
  inserted++;
}
try{ await relay.viewport.scrollAndZoomIntoView([parent]) }catch(e){}
return { ok:true, batch:3, inserted };
